def evaluate(expr: str) -> float:
    tokens = _tokenize(expr)
    pos = [0]

    def peek():
        return tokens[pos[0]] if pos[0] < len(tokens) else None

    def advance():
        tok = tokens[pos[0]]
        pos[0] += 1
        return tok

    def parse_expr():
        value = parse_term()
        while peek() in ('+', '-'):
            op = advance()
            rhs = parse_term()
            value = value + rhs if op == '+' else value - rhs
        return value

    def parse_term():
        value = parse_unary()
        while peek() in ('*', '/'):
            op = advance()
            rhs = parse_unary()
            value = value * rhs if op == '*' else value / rhs
        return value

    def parse_unary():
        if peek() == '-':
            advance()
            return -parse_unary()
        return parse_power()

    def parse_power():
        base = parse_primary()
        if peek() == '**':
            advance()
            exponent = parse_unary()
            return base ** exponent
        return base

    def parse_primary():
        tok = peek()
        if tok is None:
            raise ValueError("Unexpected end of expression")
        if tok == '(':
            advance()
            value = parse_expr()
            if peek() != ')':
                raise ValueError("Expected ')'")
            advance()
            return value
        if isinstance(tok, float):
            advance()
            return tok
        raise ValueError(f"Unexpected token {tok!r}")

    result = parse_expr()
    if pos[0] != len(tokens):
        raise ValueError("Unexpected trailing input")
    return float(result)


def _tokenize(expr: str):
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        if c.isdigit() or c == '.':
            j = i
            has_dot = False
            has_digit = False
            while j < n and (expr[j].isdigit() or (expr[j] == '.' and not has_dot)):
                if expr[j] == '.':
                    has_dot = True
                else:
                    has_digit = True
                j += 1
            if not has_digit:
                raise ValueError(f"Invalid number at position {i}")
            tokens.append(float(expr[i:j]))
            i = j
            continue
        if c == '*':
            if i + 1 < n and expr[i + 1] == '*':
                tokens.append('**')
                i += 2
            else:
                tokens.append('*')
                i += 1
            continue
        if c in '+-/()':
            tokens.append(c)
            i += 1
            continue
        raise ValueError(f"Illegal character {c!r} at position {i}")
    return tokens
